#!/usr/bin/env node
import fs from "fs";
import path from "path";
import readline from "readline";
import { resolveLang, makeT, packageDirFromImportMeta } from "../lib/i18n.js";

// Reads the .shane-new-doc.json config file from the project root
// (generated by create-shane-new-doc or postinstall, can also be created/edited by hand)
// imgDir: image folder, defaults to public/img
// lang: "en" | "zh-cn", saved once at install time -- see lib/i18n.js for the
// full resolution order (a one-off --lang flag on this command always wins)
//
// Note: docsDir is intentionally NOT configurable -- Starlight's docsLoader()
// always reads from src/content/docs/, that's a framework-level convention
// this CLI can't change. Setting it would have no effect and would just make
// the generated docs land in a folder Starlight never renders.
//
// author is likewise never read/written: Starlight's docs schema only has
// title / description by default, no author field, and writing one into the
// frontmatter would fail zod validation (unlike shane-new-post, where the
// astro-paper post schema already includes author).
let CONFIG = {};

try {
  const configPath = path.join(process.cwd(), ".shane-new-doc.json");
  if (fs.existsSync(configPath)) {
    CONFIG = JSON.parse(fs.readFileSync(configPath, "utf8"));
  }
} catch {
  CONFIG = {};
}

const DOC_ROOT = "src/content/docs";
const IMG_ROOT = CONFIG.imgDir || "public/img";

const PACKAGE_DIR = packageDirFromImportMeta(import.meta.url);
const { lang } = resolveLang({ config: CONFIG });
const t = makeT(PACKAGE_DIR, lang);

function clean(value) {
  return String(value ?? "").trim();
}

function yaml(value) {
  return clean(value)
    .replaceAll("\\", "\\\\")
    .replaceAll('"', '\\"')
    .replaceAll("\n", " ");
}

function checkFilename(filename) {
  const invalid = /[\\/:*?"<>|]/;
  if (invalid.test(filename) || filename.includes("..")) {
    throw new Error(t("errInvalidFilename"));
  }
}

function checkDirectory(directory) {
  const invalid = /[\\/:*?"<>|]/;
  if (invalid.test(directory) || directory.includes("..")) {
    throw new Error(t("errInvalidDirectory"));
  }
}

function checkPath(directory, filename) {
  const target = path.resolve(DOC_ROOT, directory, filename);
  const root = path.resolve(DOC_ROOT);
  if (target !== root && !target.startsWith(root + path.sep)) {
    throw new Error(t("errEscapePath"));
  }
}

function checkOrder(order) {
  if (order && Number.isNaN(Number(order))) {
    throw new Error(t("errOrderNaN"));
  }
}

function createDoc({ directory, filename, title = "", description = "", order = "", useMdx = false }) {
  checkDirectory(directory);
  checkFilename(filename);
  checkOrder(order);

  title = title || filename.replace(/\.mdx?$/, "");

  if (filename.endsWith(".md") || filename.endsWith(".mdx")) {
    console.log(t("infoExtensionIgnored"));
  } else {
    filename += useMdx ? ".mdx" : ".md";
  }

  checkPath(directory, filename);

  const dir = path.join(DOC_ROOT, directory);
  let filePath = path.join(dir, filename);

  // Auto-increment the filename on collision (md/mdx or same name) instead of overwriting
  if (fs.existsSync(filePath)) {
    const ext = path.extname(filename);
    const baseName = path.basename(filename, ext);
    let count = 2;
    do {
      filename = `${baseName}(${count})${ext}`;
      filePath = path.join(dir, filename);
      count++;
    } while (fs.existsSync(filePath));

    console.log(t("infoRenamed", { filename }));
  }

  fs.mkdirSync(dir, { recursive: true });

  let content = "---\n";
  content += `title: "${yaml(title)}"\n`;
  if (description) content += `description: "${yaml(description)}"\n`;
  if (order) content += `sidebar:\n  order: ${Number(order)}\n`;
  content += "---\n\n# " + title + "\n";

  fs.writeFileSync(filePath, content, "utf8");

  const imgDirName = filename.replace(/\.mdx?$/, "");
  const imgDir = path.join(IMG_ROOT, directory, imgDirName);
  fs.mkdirSync(imgDir, { recursive: true });

  console.log(t("createdHeader"));
  console.log(filePath);
  console.log(t("imgFolderLabel", { dir: imgDir }));
}

function parseSlashArgs(args) {
  const result = {};
  result.directory = args[0] || "";
  result.filename = args[1] || "";

  const parts = args.slice(2).flatMap(arg => arg.split(/[/\\]/).filter(Boolean));

  for (const item of parts) {
    const index = item.indexOf(":");
    if (index === -1) continue;
    const key = item.slice(0, index).trim().toLowerCase();
    const value = item.slice(index + 1).trim();
    const alias = {
      desc: "description",
      md: "mdx",
      order: "order",
      sidebarorder: "order",
      dir: "directory"
    };
    result[alias[key] || key] = value;
  }

  return result;
}

function commandMode(args) {
  const parsed = parseSlashArgs(args);

  if (!parsed.directory || !parsed.filename) {
    console.log(t("usage"));
    process.exit(1);
  }

  try {
    createDoc({
      directory: parsed.directory,
      filename: parsed.filename,
      title: parsed.title || "",
      description: parsed.description || "",
      order: parsed.order || "",
      useMdx: ["true","t"].includes(String(parsed.mdx || "").toLowerCase()),
    });
  } catch (error) {
    console.log("❌ " + error.message);
    process.exit(1);
  }
}

async function interactiveMode() {
  const rl = readline.createInterface({ input: process.stdin, output: process.stdout });
  const ask = text => new Promise(resolve => rl.question(text, answer => resolve(clean(answer))));

  console.log(t("interactiveTitle"));

  let directory = "";
  while (!directory) directory = await ask(t("askDirectory"));

  let filename = "";
  while (!filename) filename = await ask(t("askFilename"));

  try {
    checkFilename(filename);
  } catch (error) {
    console.log("❌ " + error.message);
    rl.close();
    return;
  }

  const title = await ask(t("askTitle"));
  const description = await ask(t("askDescription"));

  let order = "";
  while (true) {
    order = await ask(t("askOrder"));
    if (!order || !Number.isNaN(Number(order))) break;
    console.log("❌ " + t("errOrderNaN"));
  }

  const mdxInput = await ask(t("askMdx"));
  rl.close();

  try {
    createDoc({ directory, filename, title, description, order, useMdx: /^y(es)?$/i.test(mdxInput) });
  } catch (error) {
    console.log("❌ " + error.message);
  }
}

// Strip out any --lang=xx / --en / --zh-cn flag before deciding which mode to
// run in and before parsing positional args -- it's consumed by resolveLang()
// above via process.argv directly, so it must not be mistaken for the
// directory/filename positionals.
const args = process.argv.slice(2).filter(arg =>
  !/^--lang=/i.test(arg) && !["--en", "--english", "--zh", "--zh-cn", "--chinese"].includes(arg)
);

if (args.length >= 2 && !args.includes("--dir") && !args.includes("--file")) {
  commandMode(args);
} else {
  interactiveMode();
}
